import { requireNativeView } from 'expo';
import { type ColorValue, type TextStyle, type ViewProps } from 'react-native';
import type { SFSymbol } from 'sf-symbols-typescript';

import type {
  RouterToolbarHostProps,
  RouterToolbarItemProps,
  RouterToolbarMenuProps,
} from './native.types';

const RouterToolbarHostView: React.ComponentType<ViewProps> = requireNativeView(
  'ExpoRouterToolbarModule',
  'RouterToolbarHostView'
);
export function RouterToolbarHost(props: RouterToolbarHostProps) {
  return (
    <RouterToolbarHostView
      {...props}
      style={{
        position: 'absolute',
        top: 0,
        left: 0,
        width: 1,
        height: 1,
        backgroundColor: 'transparent',
      }}
    />
  );
}

const RouterToolbarItemView: React.ComponentType<
  ViewProps & {
    identifier: string;
    title?: string;
    systemImageName?: SFSymbol;
    xcassetName?: string;
    image?: number;
    imageRenderingMode?: 'template' | 'original';
    type?: string;
    titleStyle?: {
      fontFamily?: string;
      fontSize?: number;
      fontWeight?: TextStyle['fontWeight'];
      color?: ColorValue;
    };
    tintColor?: ColorValue;
  }
> = requireNativeView('ExpoRouterToolbarModule', 'RouterToolbarItemView');

export function RouterToolbarItem(props: RouterToolbarItemProps) {
  // Needed to pass shared object ID to native side
  const imageObjectId = (
    props.image as
      | {
          __expo_shared_object_id__: number;
        }
      | undefined
  )?.__expo_shared_object_id__;
  // Destructure `source` to avoid passing Android-only prop to the iOS native view
  const { source, ...nativeProps } = props;
  return <RouterToolbarItemView {...nativeProps} image={imageObjectId} />;
}

// iOS uses NativeToolbarMenu/NativeLinkPreviewAction for menus — this is a no-op.
export function RouterToolbarMenu(props: RouterToolbarMenuProps) {
  return null;
}
